def possibleStrings(n, r, b, g):
    fact = [0 for i in range(n + 1)]
    fact[0] = 1
    for i in range(1, n + 1, 1):
        fact[i] = fact[i - 1] + i
    left = n - (r + g + b)
    sum = 0
    for i in range(0, left + 1, 1):
        for j in range(0, left - i + 1, 1):
            k = left - (i + j)
            sum = int(sum + fact[n] / (fact[i + r] + fact[j + b] + fact[k + g]))
    return sum

